Here's a complete example of data-driven MSTest tests for your `PriceCalculator`:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

[TestClass]
public class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // --- DataRow: inline test cases for CalculateTotal ---

    [TestMethod]
    [DataRow(1, 10.00, 0.0, 10.00)]
    [DataRow(3, 5.50, 0.0, 16.50)]
    [DataRow(0, 99.99, 0.0, 0.0)]
    [DataRow(2, 10.00, 2.50, 22.50)]   // with shipping
    [DataRow(1, 0.0, 5.00, 5.00)]      // zero price + shipping
    public void CalculateTotal_WithVariousInputs_ReturnsExpected(
        int quantity, double unitPrice, double shipping, double expected)
    {
        var result = _calculator.CalculateTotal(quantity, (decimal)unitPrice, (decimal)shipping);

        Assert.AreEqual((decimal)expected, result, 0.001m);
    }

    // --- DataRow: inline test cases for ApplyDiscount ---

    [TestMethod]
    [DataRow(100.00, 10, 90.00)]
    [DataRow(100.00, 0, 100.00)]
    [DataRow(50.00, 50, 25.00)]
    [DataRow(200.00, 100, 0.00)]
    [DataRow(0.00, 25, 0.00)]
    public void ApplyDiscount_WithVariousInputs_ReturnsExpected(
        double subtotal, int discountPercent, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)subtotal, discountPercent);

        Assert.AreEqual((decimal)expected, result, 0.001m);
    }

    // --- DynamicData: complex/reusable test cases from a method ---

    [TestMethod]
    [DynamicData(nameof(GetDiscountEdgeCases), DynamicDataSourceType.Method)]
    public void ApplyDiscount_EdgeCases_ReturnsExpected(
        decimal subtotal, int discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(subtotal, discountPercent);

        Assert.AreEqual(expected, result);
    }

    private static IEnumerable<object[]> GetDiscountEdgeCases()
    {
        yield return new object[] { 999.99m, 1, 989.99m };   // minimal discount
        yield return new object[] { 0.01m, 99, 0.0001m };    // near-zero remainder
        yield return new object[] { 1000.00m, 15, 850.00m }; // typical bulk discount
    }

    // --- DynamicData: from a property ---

    [TestMethod]
    [DynamicData(nameof(TotalWithDiscountCases), DynamicDataSourceType.Property)]
    public void CalculateTotal_ThenApplyDiscount_ReturnsExpected(
        int qty, decimal price, int discountPct, decimal expected)
    {
        var total = _calculator.CalculateTotal(qty, price, 0m);
        var result = _calculator.ApplyDiscount(total, discountPct);

        Assert.AreEqual(expected, result);
    }

    private static IEnumerable<object[]> TotalWithDiscountCases => new[]
    {
        new object[] { 2, 50.00m, 10, 90.00m },
        new object[] { 5, 20.00m, 25, 75.00m },
        new object[] { 1, 100.00m, 0, 100.00m },
    };

    // --- Negative testing with DataRow ---

    [TestMethod]
    [DataRow(-1, 10.00)]
    [DataRow(1, -5.00)]
    public void CalculateTotal_InvalidInputs_ThrowsArgumentException(
        int quantity, double unitPrice)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _calculator.CalculateTotal(quantity, (decimal)unitPrice, 0m));
    }

    [TestMethod]
    [DataRow(100.00, -1)]
    [DataRow(100.00, 101)]
    public void ApplyDiscount_InvalidPercent_ThrowsArgumentOutOfRangeException(
        double subtotal, int discountPercent)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount((decimal)subtotal, discountPercent));
    }
}
```

**Key best practices shown:**

| Technique | When to use |
|-----------|-------------|
| `[DataRow]` | Simple inline values (primitives only) |
| `[DynamicData]` method | Complex types, computed values, or many cases |
| `[DynamicData]` property | Reusable datasets shared across tests |

**Notes:**
- `DataRow` only supports compile-time constants (`double`, not `decimal`), so cast in the method body.
- `DynamicData` supports `decimal` and complex objects directly.
- Each `[TestMethod]` tests one logical behavior; parameterization covers input variety.
- Use `[TestInitialize]` for shared setup instead of constructors.
